/**
 * traceGroupLayout — a group-based layout for footprint trace charts, designed
 * the way a layout engineer reasons about structured flowcharts: NOT by tuning
 * a generic Sugiyama/dagre pass, but by ranking nodes into bands and centering
 * each MERGE under the SPAN of its inputs, so the layout's correctness falls out
 * BY CONSTRUCTION.
 *
 * The mental model (groups):
 *   - A SEQUENCE is a single-in/single-out chain → stacked vertically, each node
 *     inheriting its predecessor's x (a straight spine; the downstream
 *     `snapLinearSuccessors` pass keeps it pixel-exact).
 *   - A FORK (a node with ≥2 branch children) → its children spread across the
 *     next band; the children ARE the parallel group.
 *   - A MERGE (a node with ≥2 incoming edges) → centered under the combined
 *     visual SPAN of its inputs. This handles STAGGERED merges with zero
 *     special-casing: longest-path ranking puts a merge one band below its
 *     deepest input, and span-centering places it symmetrically under inputs
 *     that may sit at different bands and have very different widths.
 *
 * For the agent merge-tree this yields: messageAPI centered under
 * {system-prompt, messages}; call-llm centered under the span of
 * {messageAPI, tools} (tools bypasses messageAPI's band — a staggered merge);
 * route + its branches symmetric below; the loop excluded from layout (drawn as
 * a right-margin back-edge by `LoopBackEdge`).
 *
 * Contract: pure `(TraceGraph) => TraceGraph`, sets `position` (top-left) on
 * every node, parent-relative for `parentId` nodes — same as `dagreTraceLayout`.
 * Reuses `sizeOf` / `NodeSizeResolver` / size defaults from `dagreTraceLayout`
 * (so the group-container "style-wins" exception + any consumer sizing behave
 * identically), and composes with the existing `createSnappedDagreLayout` +
 * `wrapInMainChartBox` passes — no duplication.
 */

import type { TraceGraph, TraceNode } from "../traceStructureRecorder";
import type { TraceFlowLayout } from "../TraceFlow";
import {
  sizeOf,
  DEFAULT_NODE_W,
  DEFAULT_NODE_H,
  type NodeSizeResolver,
  type SiblingOrderResolver,
} from "./dagreTraceLayout";

export interface TraceGroupLayoutOptions {
  /** Vertical gap between rank bands (px). Default 80. */
  readonly rankSep?: number;
  /** Horizontal gap between siblings within a band (px). Default 60. */
  readonly nodeSep?: number;
  /** Fallback node footprint when a node carries no explicit size. */
  readonly nodeWidth?: number;
  readonly nodeHeight?: number;
  /** Per-node size resolver (see `NodeSizeResolver`). Resolution order matches
   *  `dagreTraceLayout.sizeOf`. */
  readonly nodeSize?: NodeSizeResolver;
  /** Left-to-right order for a fork's children within their band (see
   *  `SiblingOrderResolver`). Default = edge-insertion order. */
  readonly siblingOrder?: SiblingOrderResolver;
  /** Bottom-up merge re-centering pass. Default true; off = pass-1 only (debug). */
  readonly enableMergeCentering?: boolean;
  /**
   * How a MERGE (join) node is horizontally placed relative to its inputs:
   *   - `"span"` (default) — centered under the combined visual SPAN of its
   *     inputs. Faithful "this node's data comes from those boxes", but when a
   *     join's inputs are the splayed children of a fork, the join lands under
   *     the splay (off the trunk) and the main path ZIG-ZAGS.
   *   - `"fork-origin"` — aligned with the FORK the inputs re-converge from
   *     (their lowest common ancestor). A join returns to its fork's axis, so
   *     the trunk (root → joins → tail) renders as ONE STRAIGHT centered column
   *     with the branches splaying symmetrically around it. Nested forks return
   *     to their INNER fork. Use for "read it as a sequence with side-inputs"
   *     charts.
   * Default `"span"` (unchanged behavior for existing consumers).
   */
  readonly mergeAlign?: "span" | "fork-origin";
}

interface Adjacency {
  readonly preds: Map<string, string[]>;
  readonly branchSuccs: Map<string, string[]>;
  readonly width: Map<string, number>;
  readonly height: Map<string, number>;
  /** Nodes whose footprint came from the consumer `nodeSize` resolver — their
   *  resolved size is stamped onto `style` at emit so the node RENDERS at the
   *  same footprint it was LAID OUT for (paint matches layout). Mirrors
   *  `dagreTraceLayout`'s `resolvedStyleSizes`. */
  readonly resolvedStyle: Map<string, { width: number; height: number }>;
}

/**
 * Build forward adjacency from the graph. Loop edges are excluded (visual-only
 * back-edges), duplicate (source,target) pairs are deduped (a doubled edge must
 * not fake a fork/merge), and edges to missing nodes are dropped.
 */
function buildAdjacency(
  graph: TraceGraph,
  fallbackW: number,
  fallbackH: number,
  nodeSize?: NodeSizeResolver,
): Adjacency {
  const preds = new Map<string, string[]>();
  const branchSuccs = new Map<string, string[]>();
  const width = new Map<string, number>();
  const height = new Map<string, number>();
  const resolvedStyle = new Map<string, { width: number; height: number }>();
  const ids = new Set<string>();

  for (const n of graph.nodes) {
    ids.add(n.id);
    const s = sizeOf(n, fallbackW, fallbackH, nodeSize);
    width.set(n.id, s.width);
    height.set(n.id, s.height);
    // Stamp only when sizeOf actually USED the resolver (resolved == final), so
    // a group container's authoritative `style` footprint is NOT overwritten
    // (mirrors dagreTraceLayout). Default/style-sized nodes already render right.
    const resolved = nodeSize?.(n);
    if (resolved && resolved.width === s.width && resolved.height === s.height) {
      resolvedStyle.set(n.id, resolved);
    }
    preds.set(n.id, []);
    branchSuccs.set(n.id, []);
  }

  const seen = new Set<string>();
  for (const e of graph.edges) {
    if (e.data?.kind === "loop") continue; // visual back-edge — never shapes layout
    if (!ids.has(e.source) || !ids.has(e.target)) continue;
    const key = `${e.source}�${e.target}`;
    if (seen.has(key)) continue; // dedupe — a doubled edge can't fake a fork/merge
    seen.add(key);
    preds.get(e.target)!.push(e.source);
    if (e.data?.kind === "fork-branch" || e.data?.kind === "decision-branch") {
      branchSuccs.get(e.source)!.push(e.target);
    }
  }
  return { preds, branchSuccs, width, height, resolvedStyle };
}

/**
 * Longest-path rank for every node (memoized DFS). A merge lands at
 * `max(input ranks) + 1`, so it is ALWAYS below every input regardless of how
 * many bands an input skips — the staggered-merge guarantee. Sources are rank 0.
 * A non-loop cycle (malformed input) is broken at the in-progress node (treated
 * as a rank-0 contribution) rather than recursing forever.
 */
function assignRanks(preds: Map<string, string[]>, ids: readonly string[]): Map<string, number> {
  const rank = new Map<string, number>();
  const inProgress = new Set<string>();
  const visit = (id: string): number => {
    const memo = rank.get(id);
    if (memo !== undefined) return memo;
    if (inProgress.has(id)) return 0; // cycle guard (DAG once loops excluded)
    inProgress.add(id);
    const ps = preds.get(id) ?? [];
    let r = 0;
    for (const p of ps) {
      const pr = visit(p);
      if (pr + 1 > r) r = pr + 1;
    }
    inProgress.delete(id);
    rank.set(id, r);
    return r;
  };
  for (const id of ids) visit(id);
  return rank;
}

/** Center-x under the combined visual SPAN of the given nodes (min left edge ..
 *  max right edge). For equal widths this equals the plain center-average; for
 *  asymmetric widths it centers under the span (no drift toward the narrow side). */
function spanCenter(ids: readonly string[], center: Map<string, number>, width: Map<string, number>): number {
  let left = Infinity;
  let right = -Infinity;
  for (const id of ids) {
    const c = center.get(id);
    if (c === undefined) continue;
    const w = width.get(id) ?? 0;
    if (c - w / 2 < left) left = c - w / 2;
    if (c + w / 2 > right) right = c + w / 2;
  }
  if (!Number.isFinite(left)) return 0;
  return (left + right) / 2;
}

/** All ancestors of `start` (INCLUDING itself), walking `preds` up. Cycle-safe
 *  via a visited set; loop edges are already excluded from `preds`. */
function ancestorsOf(start: string, preds: Map<string, string[]>): Set<string> {
  const seen = new Set<string>();
  const stack = [start];
  while (stack.length) {
    const n = stack.pop()!;
    if (seen.has(n)) continue;
    seen.add(n);
    for (const p of preds.get(n) ?? []) if (!seen.has(p)) stack.push(p);
  }
  return seen;
}

/**
 * The LOWEST COMMON ANCESTOR of a merge's inputs — the fork those inputs
 * re-converge from. Computed as the deepest (highest-rank) node present in EVERY
 * input's ancestor set. Used by `mergeAlign: "fork-origin"` so a join aligns
 * with its fork (the trunk returns to one axis) instead of centering under the
 * splayed branches. For nested forks this returns the INNER fork (not the outer
 * root), keeping each sub-trunk straight. Returns `undefined` when the inputs
 * share no common ancestor (disjoint sources) → caller falls back to span.
 */
function lowestCommonAncestor(
  inputs: readonly string[],
  preds: Map<string, string[]>,
  rank: Map<string, number>,
): string | undefined {
  if (inputs.length === 0) return undefined;
  let common = ancestorsOf(inputs[0]!, preds);
  for (let i = 1; i < inputs.length && common.size > 0; i++) {
    const a = ancestorsOf(inputs[i]!, preds);
    common = new Set([...common].filter((x) => a.has(x)));
  }
  let best: string | undefined;
  let bestRank = -Infinity;
  for (const id of common) {
    const r = rank.get(id) ?? -Infinity;
    if (r > bestRank) (bestRank = r), (best = id);
  }
  return best;
}

/**
 * Order the ids within one band left-to-right. When they all share a single
 * fork parent and a `siblingOrder` is supplied, honor it; otherwise sort by the
 * primary predecessor's center-x (so children stay under their parents), then
 * by original insertion order.
 */
function orderBand(
  ids: readonly string[],
  preds: Map<string, string[]>,
  center: Map<string, number>,
  insertionIndex: Map<string, number>,
  siblingOrder?: SiblingOrderResolver,
): string[] {
  if (siblingOrder && ids.length > 1) {
    const parents = new Set(ids.map((id) => preds.get(id)?.[0]));
    if (parents.size === 1) {
      const parent = [...parents][0];
      if (parent !== undefined) {
        const ordered = siblingOrder(parent, ids);
        const used = new Set<string>();
        const out: string[] = [];
        for (const id of ordered) if (ids.includes(id) && !used.has(id)) (out.push(id), used.add(id));
        for (const id of ids) if (!used.has(id)) out.push(id);
        return out;
      }
    }
  }
  return [...ids].sort((a, b) => {
    const pa = preds.get(a)?.[0];
    const pb = preds.get(b)?.[0];
    const ca = pa !== undefined ? center.get(pa) : undefined;
    const cb = pb !== undefined ? center.get(pb) : undefined;
    if (ca !== undefined && cb !== undefined && ca !== cb) return ca - cb;
    return (insertionIndex.get(a) ?? 0) - (insertionIndex.get(b) ?? 0);
  });
}

/**
 * Lay out a `TraceGraph` by rank bands + span-centered merges. Returns a NEW
 * graph with each node's `position` set. Edges pass through by reference.
 */
export function traceGroupLayout(graph: TraceGraph, options: TraceGroupLayoutOptions = {}): TraceGraph {
  if (graph.nodes.length === 0) return { nodes: graph.nodes, edges: graph.edges };
  if (graph.nodes.length === 1) {
    const only = graph.nodes[0]!;
    return { nodes: [{ ...only, position: { x: 0, y: 0 } }], edges: graph.edges };
  }

  const rankSep = options.rankSep ?? 80;
  const nodeSep = options.nodeSep ?? 60;
  const fallbackW = options.nodeWidth ?? DEFAULT_NODE_W;
  const fallbackH = options.nodeHeight ?? DEFAULT_NODE_H;
  const mergeCentering = options.enableMergeCentering ?? true;
  const mergeAlign = options.mergeAlign ?? "span";

  const ids = graph.nodes.map((n) => n.id);
  const insertionIndex = new Map(ids.map((id, i) => [id, i]));
  const { preds, branchSuccs, width, height, resolvedStyle } = buildAdjacency(
    graph,
    fallbackW,
    fallbackH,
    options.nodeSize,
  );
  const rank = assignRanks(preds, ids);

  // Orphans (no rank — only possible via the cycle guard) stack below.
  let maxRank = 0;
  for (const r of rank.values()) if (r > maxRank) maxRank = r;
  for (const id of ids) if (!rank.has(id)) rank.set(id, maxRank + 1);
  maxRank = 0;
  for (const r of rank.values()) if (r > maxRank) maxRank = r;

  // Band → ids; band → top-y (cumulative by tallest node per band + rankSep).
  const byRank = new Map<number, string[]>();
  const bandMaxH = new Map<number, number>();
  for (const id of ids) {
    const r = rank.get(id)!;
    (byRank.get(r) ?? byRank.set(r, []).get(r)!).push(id);
    bandMaxH.set(r, Math.max(bandMaxH.get(r) ?? 0, height.get(id)!));
  }
  const bandTop = new Map<number, number>();
  let yAcc = 0;
  for (let r = 0; r <= maxRank; r++) {
    bandTop.set(r, yAcc);
    yAcc += (bandMaxH.get(r) ?? fallbackH) + rankSep;
  }

  // ── PASS 1 — top-down placement. Every node's positioning dependency lives
  //    in a HIGHER band (already placed): a sequence inherits its predecessor's
  //    x; a merge centers under its inputs' span; a fork's children are placed
  //    as a GROUP centered under the fork parent (symmetric spread). A cursor
  //    prevents overlap with the prior node/group in the band. ──
  const center = new Map<string, number>();
  // A merge's center: under its inputs' SPAN (default), or — in "fork-origin"
  // mode — on the axis of the fork the inputs re-converge from (their lowest
  // common ancestor), which keeps the trunk straight. The LCA is strictly
  // higher-rank than the merge, so it is already placed when read (top-down
  // PASS 1 and bottom-up PASS 2 both satisfy this). Falls back to span when the
  // inputs share no common ancestor.
  const mergeCenterX = (ps: readonly string[]): number => {
    if (mergeAlign === "fork-origin") {
      const lca = lowestCommonAncestor(ps, preds, rank);
      const lcaC = lca !== undefined ? center.get(lca) : undefined;
      if (lcaC !== undefined) return lcaC;
    }
    return spanCenter(ps, center, width);
  };
  for (let r = 0; r <= maxRank; r++) {
    const band = orderBand(byRank.get(r) ?? [], preds, center, insertionIndex, options.siblingOrder);
    let cursor = -Infinity; // left edge available for the next node/group
    let i = 0;
    while (i < band.length) {
      const id = band[i]!;
      const ps = preds.get(id) ?? [];
      const parent = ps.length === 1 ? ps[0]! : undefined;
      const parentBranches = parent !== undefined ? branchSuccs.get(parent) ?? [] : [];
      // Only a real BRANCH child (fork-branch/decision-branch edge) is centered
      // as part of the fork group — a plain `next` child of a fork parent is a
      // sequence node, not a parallel branch, so it must NOT be swept in.
      const isForkChild = parent !== undefined && parentBranches.length >= 2 && parentBranches.includes(id);

      if (isForkChild) {
        // Contiguous run of BRANCH siblings sharing this fork parent → center it.
        const run: string[] = [];
        let j = i;
        while (j < band.length) {
          const cand = band[j]!;
          const cps = preds.get(cand) ?? [];
          if (cps.length === 1 && cps[0] === parent && parentBranches.includes(cand)) run.push(cand), j++;
          else break;
        }
        const totalW = run.reduce((s, rid) => s + width.get(rid)!, 0) + (run.length - 1) * nodeSep;
        let left = (center.get(parent) ?? 0) - totalW / 2;
        if (cursor !== -Infinity && left < cursor) left = cursor; // no overlap with prior
        let x = left;
        for (const rid of run) {
          const w = width.get(rid)!;
          center.set(rid, x + w / 2);
          x += w + nodeSep;
        }
        cursor = x;
        i = j;
      } else {
        const w = width.get(id)!;
        let desired: number;
        if (ps.length === 0) desired = (cursor === -Infinity ? 0 : cursor) + w / 2;
        else if (ps.length === 1) desired = center.get(ps[0]!) ?? 0; // sequence: inherit pred x
        else desired = mergeCenterX(ps); // merge: span- or fork-origin-aligned
        const cursorCenter = cursor === -Infinity ? -Infinity : cursor + w / 2;
        const c = Math.max(cursorCenter, desired); // never overlap the left sibling
        center.set(id, c);
        cursor = c + w / 2 + nodeSep;
        i++;
      }
    }
  }

  // ── PASS 2 — bottom-up exact merge centering. Walk high→low rank so every
  //    merge reads finalized (strictly-higher-rank) inputs. Inputs are NOT
  //    shifted; merges sit alone in their band here, so no collision. ──
  if (mergeCentering) {
    for (let r = maxRank; r >= 1; r--) {
      for (const id of byRank.get(r) ?? []) {
        const ps = preds.get(id) ?? [];
        if (ps.length > 1) center.set(id, mergeCenterX(ps));
      }
    }
  }

  // ── EMIT — top-left positions; vertically center each node in its band;
  //    parent-relative for `parentId` nodes (mirrors dagreTraceLayout). ──
  const centerById = center;
  const positioned: TraceNode[] = graph.nodes.map((n) => {
    const r = rank.get(n.id)!;
    const w = width.get(n.id)!;
    const h = height.get(n.id)!;
    let x = (centerById.get(n.id) ?? 0) - w / 2;
    let y = (bandTop.get(r) ?? 0) + ((bandMaxH.get(r) ?? h) - h) / 2;
    if (n.parentId) {
      const pr = rank.get(n.parentId);
      const pw = width.get(n.parentId);
      const ph = height.get(n.parentId);
      if (pr !== undefined && pw !== undefined && ph !== undefined) {
        const parentX = (centerById.get(n.parentId) ?? 0) - pw / 2;
        const parentY = (bandTop.get(pr) ?? 0) + ((bandMaxH.get(pr) ?? ph) - ph) / 2;
        x -= parentX;
        y -= parentY;
      }
    }
    // Stamp the resolver footprint onto `style` so the node RENDERS at the same
    // size it was laid out for (paint matches layout) — otherwise a funnel-sized
    // merge would render at its intrinsic width and its visual center would drift.
    const styleSize = resolvedStyle.get(n.id);
    if (styleSize) {
      return { ...n, position: { x, y }, style: { ...(n.style ?? {}), width: styleSize.width, height: styleSize.height } };
    }
    return { ...n, position: { x, y } };
  });

  return { nodes: positioned, edges: graph.edges };
}

/**
 * Build a `TraceFlowLayout` from group-layout options. Pass to
 * `<TraceFlow layout={...}>` / `<TracedFlow layout={...}>`, or wrap with the
 * existing `createSnappedDagreLayout(base, opts)` (it is layout-engine-agnostic)
 * and/or `wrapInMainChartBox`.
 */
export function createTraceGroupLayout(options: TraceGroupLayoutOptions = {}): TraceFlowLayout {
  return (graph: TraceGraph) => traceGroupLayout(graph, options);
}
